2035 static Value *simplifyAndOrWithICmpEq(unsigned Opcode, Value *Op0, Value *Op1,
2036                                       const SimplifyQuery &Q,
2037                                       unsigned MaxRecurse) {
2038   assert((Opcode == Instruction::And || Opcode == Instruction::Or) &&
2039          "Must be and/or");
2040   ICmpInst::Predicate Pred;
2041   Value *A, *B;
2042   if (!match(Op0, m_ICmp(Pred, m_Value(A), m_Value(B))) ||
2043       !ICmpInst::isEquality(Pred))
2044     return nullptr;
2045 
2046   auto Simplify = [&](Value *Res) -> Value * {
2047     Constant *Absorber = ConstantExpr::getBinOpAbsorber(Opcode, Res->getType());
2048 
2049     // and (icmp eq a, b), x implies (a==b) inside x.
2050     // or (icmp ne a, b), x implies (a==b) inside x.
2051     // If x simplifies to true/false, we can simplify the and/or.
2052     if (Pred ==
2053         (Opcode == Instruction::And ? ICmpInst::ICMP_EQ : ICmpInst::ICMP_NE)) {
2054       if (Res == Absorber)
2055         return Absorber;
2056       if (Res == ConstantExpr::getBinOpIdentity(Opcode, Res->getType()))
2057         return Op0;
2058       return nullptr;
2059     }
2060 
2061     // If we have and (icmp ne a, b), x and for a==b we can simplify x to false,
2062     // then we can drop the icmp, as x will already be false in the case where
2063     // the icmp is false. Similar for or and true.
2064     if (Res == Absorber)
2065       return Op1;
2066     return nullptr;
2067   };
2068 
2069   if (Value *Res =
2070           simplifyWithOpReplaced(Op1, A, B, Q, /* AllowRefinement */ true,
2071                                  /* DropFlags */ nullptr, MaxRecurse))
2072     return Simplify(Res);
2073   if (Value *Res =
2074           simplifyWithOpReplaced(Op1, B, A, Q, /* AllowRefinement */ true,
2075                                  /* DropFlags */ nullptr, MaxRecurse))
2076     return Simplify(Res);
2077 
2078   return nullptr;
2079 }
