4373 static Value *simplifyWithOpReplaced(Value *V, Value *Op, Value *RepOp,
4374                                      const SimplifyQuery &Q,
4375                                      bool AllowRefinement,
4376                                      SmallVectorImpl<Instruction *> *DropFlags,
4377                                      unsigned MaxRecurse) {
4378   // Trivial replacement.
4379   if (V == Op)
4380     return RepOp;
4381 
4382   if (!MaxRecurse--)
4383     return nullptr;
4384 
4385   // We cannot replace a constant, and shouldn't even try.
4386   if (isa<Constant>(Op))
4387     return nullptr;
4388 
4389   auto *I = dyn_cast<Instruction>(V);
4390   if (!I)
4391     return nullptr;
4392 
4393   // The arguments of a phi node might refer to a value from a previous
4394   // cycle iteration.
4395   if (isa<PHINode>(I))
4396     return nullptr;
4397 
4398   if (Op->getType()->isVectorTy()) {
4399     // For vector types, the simplification must hold per-lane, so forbid
4400     // potentially cross-lane operations like shufflevector.
4401     if (!I->getType()->isVectorTy() || isa<ShuffleVectorInst>(I) ||
4402         isa<CallBase>(I))
4403       return nullptr;
4404   }
4405 
4406   // Don't fold away llvm.is.constant checks based on assumptions.
4407   if (match(I, m_Intrinsic<Intrinsic::is_constant>()))
4408     return nullptr;
4409 
4410   // Replace Op with RepOp in instruction operands.
4411   SmallVector<Value *, 8> NewOps;
4412   bool AnyReplaced = false;
4413   for (Value *InstOp : I->operands()) {
4414     if (Value *NewInstOp = simplifyWithOpReplaced(
4415             InstOp, Op, RepOp, Q, AllowRefinement, DropFlags, MaxRecurse)) {
4416       NewOps.push_back(NewInstOp);
4417       AnyReplaced = InstOp != NewInstOp;
4418     } else {
4419       NewOps.push_back(InstOp);
4420     }
4421   }
4422 
4423   if (!AnyReplaced)
4424     return nullptr;
4425 
4426   if (!AllowRefinement) {
4427     // General InstSimplify functions may refine the result, e.g. by returning
4428     // a constant for a potentially poison value. To avoid this, implement only
4429     // a few non-refining but profitable transforms here.
4430 
4431     if (auto *BO = dyn_cast<BinaryOperator>(I)) {
4432       unsigned Opcode = BO->getOpcode();
4433       // id op x -> x, x op id -> x
4434       if (NewOps[0] == ConstantExpr::getBinOpIdentity(Opcode, I->getType()))
4435         return NewOps[1];
4436       if (NewOps[1] == ConstantExpr::getBinOpIdentity(Opcode, I->getType(),
4437                                                       /* RHS */ true))
4438         return NewOps[0];
4439 
4440       // x & x -> x, x | x -> x
4441       if ((Opcode == Instruction::And || Opcode == Instruction::Or) &&
4442           NewOps[0] == NewOps[1])
4443         return NewOps[0];
4444 
4445       // x - x -> 0, x ^ x -> 0. This is non-refining, because x is non-poison
4446       // by assumption and this case never wraps, so nowrap flags can be
4447       // ignored.
4448       if ((Opcode == Instruction::Sub || Opcode == Instruction::Xor) &&
4449           NewOps[0] == RepOp && NewOps[1] == RepOp)
4450         return Constant::getNullValue(I->getType());
4451 
4452       // If we are substituting an absorber constant into a binop and extra
4453       // poison can't leak if we remove the select -- because both operands of
4454       // the binop are based on the same value -- then it may be safe to replace
4455       // the value with the absorber constant. Examples:
4456       // (Op == 0) ? 0 : (Op & -Op)            --> Op & -Op
4457       // (Op == 0) ? 0 : (Op * (binop Op, C))  --> Op * (binop Op, C)
4458       // (Op == -1) ? -1 : (Op | (binop C, Op) --> Op | (binop C, Op)
4459       Constant *Absorber =
4460           ConstantExpr::getBinOpAbsorber(Opcode, I->getType());
4461       if ((NewOps[0] == Absorber || NewOps[1] == Absorber) &&
4462           impliesPoison(BO, Op))
4463         return Absorber;
4464     }
4465 
4466     if (isa<GetElementPtrInst>(I)) {
4467       // getelementptr x, 0 -> x.
4468       // This never returns poison, even if inbounds is set.
4469       if (NewOps.size() == 2 && match(NewOps[1], m_Zero()))
4470         return NewOps[0];
4471     }
4472   } else {
4473     // The simplification queries below may return the original value. Consider:
4474     //   %div = udiv i32 %arg, %arg2
4475     //   %mul = mul nsw i32 %div, %arg2
4476     //   %cmp = icmp eq i32 %mul, %arg
4477     //   %sel = select i1 %cmp, i32 %div, i32 undef
4478     // Replacing %arg by %mul, %div becomes "udiv i32 %mul, %arg2", which
4479     // simplifies back to %arg. This can only happen because %mul does not
4480     // dominate %div. To ensure a consistent return value contract, we make sure
4481     // that this case returns nullptr as well.
4482     auto PreventSelfSimplify = [V](Value *Simplified) {
4483       return Simplified != V ? Simplified : nullptr;
4484     };
4485 
4486     return PreventSelfSimplify(
4487         ::simplifyInstructionWithOperands(I, NewOps, Q, MaxRecurse));
4488   }
4489 
4490   // If all operands are constant after substituting Op for RepOp then we can
4491   // constant fold the instruction.
4492   SmallVector<Constant *, 8> ConstOps;
4493   for (Value *NewOp : NewOps) {
4494     if (Constant *ConstOp = dyn_cast<Constant>(NewOp))
4495       ConstOps.push_back(ConstOp);
4496     else
4497       return nullptr;
4498   }
4499 
4500   // Consider:
4501   //   %cmp = icmp eq i32 %x, 2147483647
4502   //   %add = add nsw i32 %x, 1
4503   //   %sel = select i1 %cmp, i32 -2147483648, i32 %add
4504   //
4505   // We can't replace %sel with %add unless we strip away the flags (which
4506   // will be done in InstCombine).
4507   // TODO: This may be unsound, because it only catches some forms of
4508   // refinement.
4509   if (!AllowRefinement) {
4510     if (canCreatePoison(cast<Operator>(I), !DropFlags)) {
4511       // abs cannot create poison if the value is known to never be int_min.
4512       if (auto *II = dyn_cast<IntrinsicInst>(I);
4513           II && II->getIntrinsicID() == Intrinsic::abs) {
4514         if (!ConstOps[0]->isNotMinSignedValue())
4515           return nullptr;
4516       } else
4517         return nullptr;
4518     }
4519     Constant *Res = ConstantFoldInstOperands(I, ConstOps, Q.DL, Q.TLI);
4520     if (DropFlags && Res && I->hasPoisonGeneratingFlagsOrMetadata())
4521       DropFlags->push_back(I);
4522     return Res;
4523   }
4524 
4525   return ConstantFoldInstOperands(I, ConstOps, Q.DL, Q.TLI);
4526 }
