7195 /// Implementation of recursive simplification through an instruction's
7196 /// uses.
7197 ///
7198 /// This is the common implementation of the recursive simplification routines.
7199 /// If we have a pre-simplified value in 'SimpleV', that is forcibly used to
7200 /// replace the instruction 'I'. Otherwise, we simply add 'I' to the list of
7201 /// instructions to process and attempt to simplify it using
7202 /// InstructionSimplify. Recursively visited users which could not be
7203 /// simplified themselves are to the optional UnsimplifiedUsers set for
7204 /// further processing by the caller.
7205 ///
7206 /// This routine returns 'true' only when *it* simplifies something. The passed
7207 /// in simplified value does not count toward this.
7208 static bool replaceAndRecursivelySimplifyImpl(
7209     Instruction *I, Value *SimpleV, const TargetLibraryInfo *TLI,
7210     const DominatorTree *DT, AssumptionCache *AC,
7211     SmallSetVector<Instruction *, 8> *UnsimplifiedUsers = nullptr) {
7212   bool Simplified = false;
7213   SmallSetVector<Instruction *, 8> Worklist;
7214   const DataLayout &DL = I->getModule()->getDataLayout();
7215 
7216   // If we have an explicit value to collapse to, do that round of the
7217   // simplification loop by hand initially.
7218   if (SimpleV) {
7219     for (User *U : I->users())
7220       if (U != I)
7221         Worklist.insert(cast<Instruction>(U));
7222 
7223     // Replace the instruction with its simplified value.
7224     I->replaceAllUsesWith(SimpleV);
7225 
7226     if (!I->isEHPad() && !I->isTerminator() && !I->mayHaveSideEffects())
7227       I->eraseFromParent();
7228   } else {
7229     Worklist.insert(I);
7230   }
7231 
7232   // Note that we must test the size on each iteration, the worklist can grow.
7233   for (unsigned Idx = 0; Idx != Worklist.size(); ++Idx) {
7234     I = Worklist[Idx];
7235 
7236     // See if this instruction simplifies.
7237     SimpleV = simplifyInstruction(I, {DL, TLI, DT, AC});
7238     if (!SimpleV) {
7239       if (UnsimplifiedUsers)
7240         UnsimplifiedUsers->insert(I);
7241       continue;
7242     }
7243 
7244     Simplified = true;
7245 
7246     // Stash away all the uses of the old instruction so we can check them for
7247     // recursive simplifications after a RAUW. This is cheaper than checking all
7248     // uses of To on the recursive step in most cases.
7249     for (User *U : I->users())
7250       Worklist.insert(cast<Instruction>(U));
7251 
7252     // Replace the instruction with its simplified value.
7253     I->replaceAllUsesWith(SimpleV);
7254 
7255     if (!I->isEHPad() && !I->isTerminator() && !I->mayHaveSideEffects())
7256       I->eraseFromParent();
7257   }
7258   return Simplified;
7259 }
7260 
7261 bool llvm::replaceAndRecursivelySimplify(
7262     Instruction *I, Value *SimpleV, const TargetLibraryInfo *TLI,
7263     const DominatorTree *DT, AssumptionCache *AC,
7264     SmallSetVector<Instruction *, 8> *UnsimplifiedUsers) {
7265   assert(I != SimpleV && "replaceAndRecursivelySimplify(X,X) is not valid!");
7266   assert(SimpleV && "Must provide a simplified value.");
7267   return replaceAndRecursivelySimplifyImpl(I, SimpleV, TLI, DT, AC,
7268                                            UnsimplifiedUsers);
7269 }
